INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_NAVY_NA_L0015$$, 2027, $$Navy$$, $$PROC_NAVY$$, $$NAVY$$, NULL, $$15$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

 Justification:
 The FY 2027 request for KC-130J includes $1,601,906 thousand of discretionary funding and $1,190,000 thousand of mandatory funding for a total of $2,791,906 thousand. FY 2027 total funding supports
 the procurement of nine (9) USMC KC-130J aircraft and nine (9) USNR (two (2) discretionary; seven (7) mandatory) KC-130J aircraft, associated support equipment, and required GFE. Funding also includes
 production line Diminishing Manufacturing Sources and Material Shortages (DMSMS); support costs related to aircraft delivery; and funds an additional KC-130J Weapon Systems Trainer to meet USMC initial
 pilot production requirements. DMSMS is required to fund USMC/USNR shared costs with USAF to incorporate component redesigns into the production baseline affecting USMC/USNR aircraft deliveries
 through program completion. FY 2027 amount reflects estimated USMC/USNR shared costs in support of USAF contracting strategy.

 This budget supports aircraft delivery orders through FY 2031 via the USAF as the lead procurement agency.




