INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_NAVY_NA_L0010$$, 2027, $$Navy$$, $$PROC_NAVY$$, $$NAVY$$, NULL, $$10$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

 Justification:
 FY2027 procurement funds are required for 12 Full Rate Production aircraft with associated equipment and support in response to the Department of War's requirement to field and sustain P-8A capabilities and
 readiness necessary for a wartime tempo.

 FY2027 unit cost increased due to two year gap in US Navy production buys (FY24 was the last procurement year), sustained global commercial economic price escalation, non-recurring engineering (NRE)
 redesigns to address pervasive commercial electronics component obsolescence, and incorporation of Increment 3 Block 2 (I3B2) engineering change proposals (ECP 6/7) into the production line as approved
 engineering change orders (ECO) in order to update the aircraft combat systems configuration in accordance with the approved evolutionary acquisition strategy. The capabilities provided by the I3B2 system are
 ASW, Wide Band SATCOM, Higher Than Secret (HTS) processing, Enhanced track management (Minotaur), Applications Based Architecture (ABA) and Combat System.


 FY2027 is the last planned year of production. Final aircraft delivery is planned for 1QFY32.




